import React, { createContext, useContext, useState } from 'react';
import { format } from 'date-fns';

const ChatContext = createContext();

export const useChat = () => {
  const context = useContext(ChatContext);
  if (!context) {
    throw new Error('useChat must be used within a ChatProvider');
  }
  return context;
};

export const ChatProvider = ({ children }) => {
  // Mock chat rooms data
  const [chatRooms, setChatRooms] = useState([
    {
      id: '1',
      name: 'DeChat Genesis Holders',
      description: 'Exclusive chat for DeChat Genesis NFT holders',
      requiredNFT: 'DeChat Genesis',
      memberCount: 127,
      hasAccess: true,
      isActive: true
    },
    {
      id: '2',
      name: 'CryptoPunks Lounge',
      description: 'Chat room for CryptoPunks collectors',
      requiredNFT: 'CryptoPunks',
      memberCount: 89,
      hasAccess: true,
      isActive: false
    },
    {
      id: '3',
      name: 'BAYC Exclusive',
      description: 'Bored Ape Yacht Club members only',
      requiredNFT: 'Bored Ape Yacht Club',
      memberCount: 234,
      hasAccess: false,
      isActive: false
    }
  ]);

  // Mock messages for rooms
  const [messages, setMessages] = useState({
    '1': [
      {
        id: '1',
        sender: '0x742d35Cc6634C0532925a3b8D0C9C0E3C5d5c8E9',
        content: 'Welcome to the DeChat Genesis holders room!',
        timestamp: new Date(Date.now() - 3600000),
        ipfsHash: 'QmX1Y2Z3...',
        canMint: true
      },
      {
        id: '2',
        sender: '0x123456789abcdef123456789abcdef123456789a',
        content: 'Great to be here! Love the NFT-gated concept.',
        timestamp: new Date(Date.now() - 1800000),
        ipfsHash: 'QmA1B2C3...',
        canMint: false
      }
    ],
    '2': [
      {
        id: '3',
        sender: '0x987654321fedcba987654321fedcba987654321f',
        content: 'CryptoPunks forever! 🤖',
        timestamp: new Date(Date.now() - 7200000),
        ipfsHash: 'QmD4E5F6...',
        canMint: false
      }
    ]
  });

  // Mock private chats
  const [privateChats, setPrivateChats] = useState([
    {
      id: '1',
      participant: '0x123456789abcdef123456789abcdef123456789a',
      lastMessage: 'Hey, saw your message in the Genesis room!',
      timestamp: new Date(Date.now() - 900000),
      unreadCount: 2
    }
  ]);

  const [privateMessages, setPrivateMessages] = useState({
    '1': [
      {
        id: '1',
        sender: '0x123456789abcdef123456789abcdef123456789a',
        content: 'Hey, saw your message in the Genesis room!',
        timestamp: new Date(Date.now() - 1800000)
      },
      {
        id: '2',
        sender: '0x742d35Cc6634C0532925a3b8D0C9C0E3C5d5c8E9',
        content: 'Thanks! Yeah, really excited about this platform.',
        timestamp: new Date(Date.now() - 900000)
      }
    ]
  });

  const sendMessage = (roomId, content) => {
    const newMessage = {
      id: Date.now().toString(),
      sender: '0x742d35Cc6634C0532925a3b8D0C9C0E3C5d5c8E9',
      content,
      timestamp: new Date(),
      ipfsHash: `QmMock${Date.now()}...`,
      canMint: true
    };

    setMessages(prev => ({
      ...prev,
      [roomId]: [...(prev[roomId] || []), newMessage]
    }));
  };

  const sendPrivateMessage = (chatId, content) => {
    const newMessage = {
      id: Date.now().toString(),
      sender: '0x742d35Cc6634C0532925a3b8D0C9C0E3C5d5c8E9',
      content,
      timestamp: new Date()
    };

    setPrivateMessages(prev => ({
      ...prev,
      [chatId]: [...(prev[chatId] || []), newMessage]
    }));
  };

  const mintMessageAsNFT = async (messageId, roomId) => {
    // Mock minting process
    console.log(`Minting message ${messageId} from room ${roomId} as NFT...`);
    // Simulate blockchain transaction
    await new Promise(resolve => setTimeout(resolve, 2000));
    return {
      success: true,
      transactionHash: `0xmock${Date.now()}`,
      tokenId: Math.floor(Math.random() * 10000)
    };
  };

  const value = {
    chatRooms,
    messages,
    privateChats,
    privateMessages,
    sendMessage,
    sendPrivateMessage,
    mintMessageAsNFT
  };

  return (
    <ChatContext.Provider value={value}>
      {children}
    </ChatContext.Provider>
  );
};
